import React from 'react';
import QuestionForm from '../components/QuestionForm';

const Ask = () => {
  return (
    <div className="max-w-2xl mx-auto mt-8 p-6 bg-white rounded shadow">
      <h1 className="text-2xl mb-4">Ask a Question</h1>
      <QuestionForm />
    </div>
  );
};

export default Ask;
